-- Revert the slow flag for the types marked by the up migration. These were all seeded
-- slow = FALSE by migration 000016, so resetting them to FALSE restores the prior state.
UPDATE hash_types SET slow = FALSE WHERE id IN (
    400, 500, 1600, 1800, 7400, 7401, 3200, 7900, 15100,
    2500, 16800,
    2100, 31600,
    7100, 9200, 10000, 10900, 10901, 11900, 12000, 12001, 12100, 12800, 33900,
    8900, 9300, 15700,
    5200, 9000, 6600, 8200, 6800, 7200, 13200,
    11300, 15200, 15600, 16300,
    9400, 9500, 9600,
    11600, 12500, 13000,
    13400,
    14700, 14800,
    15300, 15310, 15900, 15910,
    19600, 19700, 19800, 19900,
    14600,
    6211, 6212, 6213, 6221, 6222, 6223, 6231, 6232, 6233, 6241, 6242, 6243,
    13711, 13712, 13713, 13721, 13722, 13723, 13731, 13732, 13733,
    13741, 13742, 13743, 13751, 13752, 13753, 13761, 13762, 13763,
    13771, 13772, 13773, 13781, 13782, 13783
